            padding: 8px 10px 3px; margin-top: 2px;
        }
        .sub-group-btn {
            display: flex; align-items: center; justify-content: space-between;
            padding: 6px 10px; border-radius: 8px; cursor: pointer;
            font-size: 0.775rem; font-weight: 600; color: #6b7280;
